query:
UPDATE anuncios 
SET costo_por_unidad = '350.00' 
WHERE cliente LIKE '%OPIOIDES%' AND tipo = 'Fijo' AND (costo_por_unidad IS NULL OR costo_por_unidad = '' OR costo_por_unidad = '0');

